import{_ as r,C as o,o as l,c as s,E as a,w as n,a as t,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Moving to Finland","description":"Immigration pathways and relocation guide for Finland","frontmatter":{"layout":"doc","title":"Moving to Finland","description":"Immigration pathways and relocation guide for Finland"},"headers":[],"relativePath":"europe/finland/moving-there.md","filePath":"europe/finland/moving-there.md","lastUpdated":null}'),h={name:"europe/finland/moving-there.md"};function u(c,e,m,p,g,f){const i=o("Badge");return l(),s("div",null,[a(i,{variant:"green"},{default:n(()=>[...e[0]||(e[0]=[t("EU/EEA: Free Movement",-1)])]),_:1}),a(i,{variant:"yellow"},{default:n(()=>[...e[1]||(e[1]=[t("Non-EU: Work or Startup Visa",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="moving-to-finland" tabindex="-1">Moving to Finland <a class="header-anchor" href="#moving-to-finland" aria-label="Permalink to &quot;Moving to Finland&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><p>Free movement applies. Register your right of residence at the Digital and Population Data Services Agency (DVV) within 3 months. Proof of employment, study, or sufficient resources is required.</p><h3 id="uk-citizens" tabindex="-1">UK Citizens <a class="header-anchor" href="#uk-citizens" aria-label="Permalink to &quot;UK Citizens&quot;">​</a></h3><p>Post-Brexit, UK citizens need a residence permit unless covered by the Withdrawal Agreement (resided in Finland before 31 December 2020). The same rules as third-country nationals apply.</p><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><ul><li><strong>Work Visa (Residence Permit for Employment)</strong>: Requires a valid job offer. Labour market testing may apply.</li><li><strong>EU Blue Card</strong>: For highly skilled workers with a salary threshold (~€57,000/year in 2025).</li><li><strong>Startup Permit</strong>: For entrepreneurs with a business idea evaluated by Business Finland. Two-year permit, renewable.</li><li><strong>ICT Specialists</strong>: For intra-company transfers.</li><li><strong>Family Ties</strong>: For spouses, registered partners, and cohabiting partners (minimum 2 years relationship).</li><li><strong>Student Visa</strong>: For university studies. Part-time work permitted (up to 30 hours/week).</li></ul><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Finland does not have a specific digital nomad visa. The Startup permit is the closest option for remote entrepreneurs. Self-employed individuals can apply for a residence permit for self-employment if they can demonstrate sufficient income and business viability.</p><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] Obtain necessary residence permit (non-EU)</li><li>[ ] Apply for a Finnish personal identity code appointment</li><li>[ ] Arrange health insurance (required for residence permit application)</li><li>[ ] Research housing in Helsinki, Tampere, Turku, or Oulu</li><li>[ ] Gather medical records and HRT documentation (translated to Finnish, Swedish, or English)</li><li>[ ] Notify your bank and redirect mail</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register with the DVV (Digital and Population Data Services Agency)</li><li>[ ] Receive personal identity code (henkilötunnus)</li><li>[ ] Register with Kela (social insurance) for healthcare coverage</li><li>[ ] Open a Finnish bank account</li><li>[ ] Find a GP (terveyskeskus)</li><li>[ ] Apply for a Finnish SIM card</li><li>[ ] Connect with Trasek or Seta for community resources</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li>Monthly rent (1-bed): €800-1,300 (Helsinki), €600-900 (Tampere, Turku)</li><li>Monthly budget (single person): €900-1,500 excluding rent</li><li>Public transport: €60-80/month (HSL Helsinki region)</li></ul><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><p>Continental with cold winters (-5 to -20°C) and mild summers (15-25°C). Northern Finland has extreme seasonal variation with midnight sun and polar night.</p><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>Finnish and Swedish are official languages. Finnish is notoriously difficult. English is very widely spoken — most Finns are fluent, especially in cities and among younger people. Government services are available in English.</p>',22))])}const b=r(h,[["render",u]]);export{v as __pageData,b as default};
